11: 	"os"
12: 	"strings"
13: 
14: 	"github.com/cilium/ebpf"
15: 	"github.com/cilium/ebpf/btf"
16: 	"k8s.io/apimachinery/pkg/util/sets"
17: 
18: 	"github.com/cilium/cilium/pkg/bpf/analyze"
19: 	"github.com/cilium/cilium/pkg/container/set"
20: 	"github.com/cilium/cilium/pkg/logging/logfields"
21: )
22: 
23: const (
24: 	callsMap = "cilium_calls"
25: )
26: 
27: // checkUnspecifiedPrograms returns an error if any of the programs in the spec
28: // are of the UnspecifiedProgram type.
29: func checkUnspecifiedPrograms(spec *ebpf.CollectionSpec) error {
30: 	for _, prog := range spec.Programs {
31: 		if prog.Type == ebpf.UnspecifiedProgram {
32: 			return fmt.Errorf("program %s has unspecified type: annotate with __section_entry or __declare_tail()", prog.Name)
33: 		}
34: 	}
35: 	return nil
36: }
37: 
38: // isEntrypoint returns true if the program is marked with the __section_entry
39: // annotation.
40: func isEntrypoint(prog *ebpf.ProgramSpec) bool {
41: 	return strings.HasSuffix(prog.SectionName, "/entry")
42: }
43: 
44: // isTailCall returns true if the program is marked with the __declare_tail()
45: // annotation.
46: func isTailCall(prog *ebpf.ProgramSpec) bool {
47: 	return strings.HasSuffix(prog.SectionName, "/tail")
48: }
49: 
50: // tailCallSlot returns the tail call slot for the given program, which must be
51: // marked with the __declare_tail() annotation. The slot is the index in the
52: // calls map that the program will be called from.
53: func tailCallSlot(prog *ebpf.ProgramSpec) (uint32, error) {
54: 	if !isTailCall(prog) {
55: 		return 0, fmt.Errorf("program %s is not a tail call", prog.Name)
56: 	}
57: 
58: 	fn := btf.FuncMetadata(&prog.Instructions[0])
59: 	if fn == nil {
60: 		return 0, fmt.Errorf("program %s has no function metadata", prog.Name)
61: 	}
62: 
63: 	for _, tag := range fn.Tags {
64: 		var slot uint32
65: 		if _, err := fmt.Sscanf(tag, fmt.Sprintf("tail:%s/%%v", callsMap), &slot); err == nil {
66: 			return slot, nil
67: 		}
68: 	}
69: 
70: 	return 0, fmt.Errorf("program %s has no tail call slot", prog.Name)
71: }
72: 
73: // resolveTailCalls populates the calls map with Programs marked with the
74: // __declare_tail annotation.
75: func resolveTailCalls(spec *ebpf.CollectionSpec) error {
76: 	// If cilium_calls map is missing, do nothing.
77: 	ms := spec.Maps[callsMap]
78: 	if ms == nil {
79: 		return nil
80: 	}
81: 
82: 	if ms.Type != ebpf.ProgramArray {
83: 		return fmt.Errorf("%s is not a program array, got %s", callsMap, ms.Type)
84: 	}
85: 
86: 	slots := make(map[uint32]struct{})
87: 	for name, prog := range spec.Programs {
88: 		if !isTailCall(prog) {
89: 			continue
90: 		}
91: 
92: 		slot, err := tailCallSlot(prog)
93: 		if err != nil {
94: 			return fmt.Errorf("getting tail call slot: %w", err)
95: 		}
96: 
97: 		if _, ok := slots[slot]; ok {
98: 			return fmt.Errorf("duplicate tail call slot %d", slot)
99: 		}
100: 		slots[slot] = struct{}{}
101: 
102: 		ms.Contents = append(ms.Contents, ebpf.MapKV{Key: slot, Value: name})
103: 	}
104: 
105: 	return nil
106: }
107: 
108: // LoadAndAssign loads spec into the kernel and assigns the requested eBPF
109: // objects to the given object. It is a wrapper around [LoadCollection]. See its
110: // documentation for more details on the loading process.
111: func LoadAndAssign(logger *slog.Logger, to any, spec *ebpf.CollectionSpec, opts *CollectionOptions) (func() error, error) {
112: 	keep, err := analyze.Fields(to)
113: 	if err != nil {
114: 		return nil, fmt.Errorf("analyzing fields of %T: %w", to, err)
115: 	}
116: 	opts.Keep = keep
117: 
118: 	coll, commit, err := LoadCollection(logger, spec, opts)
119: 	var ve *ebpf.VerifierError
120: 	if errors.As(err, &ve) {
121: 		if _, err := fmt.Fprintf(os.Stderr, "Verifier error: %s\nVerifier log: %+v\n", err, ve); err != nil {
122: 			return nil, fmt.Errorf("writing verifier log to stderr: %w", err)
123: 		}
124: 	}
125: 	if err != nil {
126: 		return nil, fmt.Errorf("loading eBPF collection into the kernel: %w", err)
127: 	}
128: 
129: 	if err := coll.Assign(to); err != nil {
130: 		return nil, fmt.Errorf("assigning eBPF objects to %T: %w", to, err)
131: 	}
132: 
133: 	return commit, nil
134: }
135: 
136: type CollectionOptions struct {
137: 	ebpf.CollectionOptions
138: 
139: 	// Replacements for datapath runtime configs declared using DECLARE_CONFIG.
140: 	// Pass a pointer to a populated object from pkg/datapath/config.
141: 	Constants any
142: 
143: 	// Maps to be renamed during loading. Key is the key in CollectionSpec.Maps,
144: 	// value is the new name.
145: 	MapRenames []map[string]string
146: 
147: 	// MapReplacements passes along the inner map to MapReplacements inside
148: 	// the embedded ebpf.CollectionOptions struct.
149: 	MapReplacements map[string]*Map
150: 
151: 	// Set of objects to keep during reachability pruning.
152: 	Keep *set.Set[string]
153: 
154: 	// ConfigDumpPath is the path to write a file to containing the constants used
155: 	// during loading, typically to be included in sysdumps.
156: 	ConfigDumpPath string
157: }
158: 
159: func (co *CollectionOptions) populateMapReplacements() {
160: 	if co.CollectionOptions.MapReplacements == nil {
161: 		co.CollectionOptions.MapReplacements = make(map[string]*ebpf.Map)
162: 	}
163: 
164: 	for n, m := range co.MapReplacements {
165: 		co.CollectionOptions.MapReplacements[n] = m.m
166: 	}
167: }
168: 
169: // LoadCollection loads the given spec into the kernel with the specified opts.
170: // Returns a function that must be called after the Collection's entrypoints are
171: // attached to their respective kernel hooks. This function commits pending map
172: // pins to the bpf file system for maps that were found to be incompatible with
173: // their pinned counterparts, or for maps with certain flags that modify the
174: // default pinning behaviour.
175: //
176: // When attaching multiple programs from the same ELF in a loop, the returned
177: // function should only be run after all entrypoints have been attached. For
178: // example, attach both bpf_host.c:cil_to_netdev and cil_from_netdev before
179: // invoking the returned function, otherwise missing tail calls will occur.
180: //
181: // Any maps marked as pinned in the spec are automatically loaded from the path
182: // given in opts.Maps.PinPath and will be used instead of creating new ones.
183: func LoadCollection(logger *slog.Logger, spec *ebpf.CollectionSpec, opts *CollectionOptions) (*ebpf.Collection, func() error, error) {
184: 	if spec == nil {
185: 		return nil, nil, errors.New("can't load nil CollectionSpec")
186: 	}
187: 
188: 	if opts == nil {
189: 		opts = &CollectionOptions{}
190: 	}
191: 
192: 	if err := checkUnspecifiedPrograms(spec); err != nil {
193: 		return nil, nil, fmt.Errorf("checking for unspecified programs: %w", err)
194: 	}
195: 
196: 	opts.populateMapReplacements()
197: 
198: 	logger.Debug("Loading Collection into kernel",
199: 		logfields.MapRenames, opts.MapRenames,
200: 		logfields.Constants, printConstants(opts.Constants),
201: 	)
202: 
203: 	// Copy spec so the modifications below don't affect the input parameter,
204: 	// allowing the spec to be safely re-used by the caller.
205: 	spec = spec.Copy()
206: 
207: 	if err := renameMaps(spec, opts.MapRenames); err != nil {
208: 		return nil, nil, err
209: 	}
210: 
211: 	if err := applyConstants(spec, opts.Constants); err != nil {
212: 		return nil, nil, fmt.Errorf("applying variable overrides: %w", err)
213: 	}
214: 
215: 	reach, err := computeReachability(spec)
216: 	if err != nil {
217: 		return nil, nil, fmt.Errorf("computing reachability: %w", err)
218: 	}
219: 
220: 	if err := removeUnusedTailcalls(spec, reach, logger); err != nil {
221: 		return nil, nil, fmt.Errorf("removing unused tail calls: %w", err)
222: 	}
223: 
224: 	if err := resolveTailCalls(spec); err != nil {
225: 		return nil, nil, fmt.Errorf("resolving tail calls: %w", err)
226: 	}
227: 
228: 	fixed := fixedResources(spec, opts.Keep)
229: 	if err := removeUnusedMaps(spec, fixed, reach, logger); err != nil {
230: 		return nil, nil, fmt.Errorf("pruning unused maps: %w", err)
231: 	}
232: 
233: 	if err := dumpConstants(spec, opts); err != nil {
234: 		return nil, nil, fmt.Errorf("writing constants: %w", err)
235: 	}
236: 
237: 	// Find and strip all CILIUM_PIN_REPLACE pinning flags before creating the
238: 	// Collection. ebpf-go will reject maps with pins it doesn't recognize.
239: 	toReplace := consumePinReplace(spec)
240: 
241: 	// Attempt to load the Collection.
242: 	coll, err := ebpf.NewCollectionWithOptions(spec, opts.CollectionOptions)
243: 
244: 	// Collect key names of maps that are not compatible with their pinned
245: 	// counterparts and remove their pinning flags.
246: 	if errors.Is(err, ebpf.ErrMapIncompatible) {
247: 		var incompatible []string
248: 		incompatible, err = incompatibleMaps(spec, opts.CollectionOptions)
249: 		if err != nil {
250: 			return nil, nil, fmt.Errorf("finding incompatible maps: %w", err)
251: 		}
252: 		toReplace = append(toReplace, incompatible...)
253: 
254: 		// Retry loading the Collection with necessary pinning flags removed.
255: 		coll, err = ebpf.NewCollectionWithOptions(spec, opts.CollectionOptions)
256: 	}
257: 
258: 	if err != nil {
259: 		return nil, nil, err
260: 	}
261: 
262: 	// In debug mode, check that no maps were freed by the kernel after loading
263: 	// the Collection.
264: 	logFreedMaps(logger, coll, fixed)
265: 
266: 	// Collect Maps that need their bpffs pins replaced. Pull out Map objects
267: 	// before returning the Collection, since commit() still needs to work when
268: 	// the Map is removed from the Collection, e.g. by [ebpf.Collection.Assign].
269: 	pins, err := mapsToReplace(toReplace, spec, coll, opts.CollectionOptions)
270: 	if err != nil {
271: 		return nil, nil, fmt.Errorf("collecting map pins to replace: %w", err)
272: 	}
273: 
274: 	// Load successful, return a function that must be invoked after attaching the
275: 	// Collection's entrypoint programs to their respective hooks.
276: 	commit := func() error {
277: 		return commitMapPins(logger, pins)
278: 	}
279: 	return coll, commit, nil
280: }
