282: // renameMaps applies renames to coll.
283: func renameMaps(coll *ebpf.CollectionSpec, allRenames []map[string]string) error {
284: 	alreadyRenamed := make(sets.Set[string])
285: 	for _, renames := range allRenames {
286: 		for name, rename := range renames {
287: 			spec := coll.Maps[name]
288: 			if spec == nil {
289: 				return fmt.Errorf("unknown map %q: can't rename to %q", name, rename)
290: 			}
291: 
292: 			if alreadyRenamed.Has(name) {
293: 				return fmt.Errorf("map %q already renamed to %q (conflicts with: %q)", name, spec.Name, rename)
294: 			}
295: 
296: 			spec.Name = rename
297: 			alreadyRenamed.Insert(name)
298: 		}
299: 	}
300: 
301: 	return nil
302: }
303: 
304: // logFreedMaps checks that no maps were freed by the kernel after loading
305: // the given Collection.
306: //
307: // Only runs in debug mode due to its runtime cost.
308: func logFreedMaps(logger *slog.Logger, coll *ebpf.Collection, fixed *set.Set[string]) {
309: 	if !logger.Enabled(context.TODO(), slog.LevelDebug) {
310: 		return
311: 	}
312: 
313: 	freed, err := freedMaps(coll, fixed)
314: 	if errors.Is(err, ebpf.ErrRestrictedKernel) {
315: 		logger.Debug("Cannot detect freed maps due to restricted kernel")
316: 		return
317: 	}
318: 	if err != nil {
319: 		logger.Debug("Error detecting freed maps", logfields.Error, err)
320: 	}
321: 
322: 	if len(freed) > 0 {
323: 		logger.Debug("Maps freed by the kernel after dead code elimination", logfields.Maps, freed)
324: 	}
325: 
326: 	logger.Debug("No freed maps found after loading Collection")
327: }
